// Set date range: last 7 days
const today = new Date();
const since = new Date(today);
since.setDate(since.getDate() - 7);

const fmt = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    since: fmt(since),
    until: fmt(today),
    accounts: [
      { id: 'act_464237024205104', name: 'Flow States Retreats' },
      { id: 'act_1426936257455201', name: 'Emma Maidment Business' },
      { id: 'act_414785961683125', name: 'Flow OS' }
    ]
  }
}];

// Split accounts into individual items for parallel fetching
const { since, until, accounts } = $input.first().json;
return accounts.map(acc => ({
  json: { account_id: acc.id, account_name: acc.name, since, until }
}));

// Build account lookup from upstream Split Accounts
const splitItems = $('Split Accounts').all();
const accountByIndex = {};
splitItems.forEach((item, idx) => {
  accountByIndex[idx] = {
    account_id: item.json.account_id,
    account_name: item.json.account_name
  };
});

const insights = [];
for (const item of $input.all()) {
  const data = item.json.data || [];
  if (data.length === 0) continue;

  // Skip campaign-list responses — only score insights rows
  if (data[0].impressions === undefined) continue;

  // Resolve which account this batch belongs to via pairedItem
  const pi = Array.isArray(item.pairedItem) ? item.pairedItem[0] : item.pairedItem;
  const pairedIdx = pi?.item ?? 0;
  const acc = accountByIndex[pairedIdx] || { account_id: '', account_name: 'Unknown' };

  for (const row of data) {
    insights.push({ ...row, account_id: acc.account_id, account_name: acc.account_name });
  }
}

if (insights.length === 0) {
  return [{ json: { accounts: [], total_adsets: 0 } }];
}

// Score each adset
const scored = insights.map(row => {
  const spend = parseFloat(row.spend || 0);
  const clicks = parseInt(row.clicks || 0);
  const impressions = parseInt(row.impressions || 0);
  const ctr = parseFloat(row.ctr || 0);
  const cpc = parseFloat(row.cpc || 0);
  const cpm = parseFloat(row.cpm || 0);
  const frequency = parseFloat(row.frequency || 0);

  const actions = row.actions || [];
  const leads = actions.find(a => a.action_type === 'lead' || a.action_type === 'offsite_conversion.fb_pixel_lead');
  const leadCount = leads ? parseInt(leads.value) : 0;
  const cpl = leadCount > 0 ? (spend / leadCount).toFixed(2) : null;

  let score = 5;
  if (ctr > 2) score += 2;
  else if (ctr > 1) score += 1;
  if (cpc < 1) score += 1;
  if (frequency > 4) score -= 2;
  if (frequency > 6) score -= 1;
  if (leadCount > 0) score += 2;
  score = Math.max(1, Math.min(10, score));

  return {
    account_id: row.account_id,
    account_name: row.account_name,
    campaign: row.campaign_name,
    adset: row.adset_name,
    spend: spend.toFixed(2),
    impressions, clicks,
    ctr: ctr.toFixed(2) + '%',
    cpc: cpc ? '$' + cpc.toFixed(2) : 'N/A',
    cpm: cpm ? '$' + cpm.toFixed(2) : 'N/A',
    frequency: frequency.toFixed(1),
    leads: leadCount,
    cpl: cpl ? '$' + cpl : 'N/A',
    performance_score: score,
    recommendation: score >= 7 ? 'SCALE' : score >= 5 ? 'MONITOR' : 'PAUSE OR REWORK'
  };
});

// Group by account
const accountMap = {};
for (const row of scored) {
  if (!accountMap[row.account_id]) {
    accountMap[row.account_id] = { account_name: row.account_name, adsets: [] };
  }
  accountMap[row.account_id].adsets.push(row);
}
for (const acc of Object.values(accountMap)) {
  acc.adsets.sort((a, b) => b.performance_score - a.performance_score);
}
// Ensure all three accounts appear, even with zero data
for (const item of $('Split Accounts').all()) {
  const id = item.json.account_id;
  if (!accountMap[id]) {
    accountMap[id] = { account_name: item.json.account_name, adsets: [] };
  }
}

return [{ json: { accounts: Object.values(accountMap), total_adsets: scored.length } }];

const aiResponse = $input.first().json;
const aiText = aiResponse?.content?.[0]?.text || '';
const { accounts, total_adsets } = $('Process & Score Insights').first().json;
const today = new Date().toLocaleDateString('en-AU', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

const accountList = accounts
  .map(a => `• ${a.account_name} — ${a.adsets.length} adsets`)
  .join('\n');

let msg = `📊 *Meta Ads Optimisation Report*\n_${today}_\n\n`;
msg += `${accountList}\n`;
msg += `*Total active adsets:* ${total_adsets}\n`;
msg += `━━━━━━━━━━━━━━━━\n\n`;
msg += aiText;

const maxLen = 4000;
if (msg.length > maxLen) msg = msg.substring(0, maxLen) + '\n_[truncated]_';

return [{ json: { report_telegram: msg } }];

// Build Anthropic API request — per-account sections
const items = $input.all();
const insightsData = items.map(item => item.json);

const systemPrompt = `You are a Meta Ads performance analyst writing a daily Telegram report for an operator managing multiple Meta ad accounts.

STRUCTURE (mandatory):
- Produce ONE report with a SEPARATE SECTION for EACH account in the data
- Each account section MUST contain:
  • Account name as a *bold heading*
  • Overview metrics: spend, leads, avg CPL, active adsets
  • Top performer(s): name, key stats, why it's working
  • Concerns: any adsets scoring below 7 or with 0 leads
  • Account-specific recommendations (1-3 tactical actions)
- If an account has zero active adsets, still include its section with a brief note ("No active delivery — recommend reactivating top historical performers" or similar)
- End with a "*Cross-account priorities*" section: the top 3 actions across all accounts, ranked by impact
- Separate accounts with a horizontal divider line: ━━━━━━━━━━━━━━━━

TELEGRAM MARKDOWN RULES (parse_mode=Markdown — strict):
- USE: *bold*, _italic_, hyphen lists
- DO NOT USE: # or ## headers (they render as literal text), pipe tables (| col | col |), ** double-asterisks, or HTML
- For section headers, use *Bold Text* on its own line
- For tabular data, use bullet lists not pipe tables
- Use emoji sparingly: 📊 for headers, ✅ for wins, ⚠️ for concerns, 💰 for spend recs

LENGTH: Under 3500 characters total. Be specific and tactical, not generic.`;

const userMessage = `Analyse this Meta Ads data (already grouped by account) and produce the per-account report:\n\n${JSON.stringify(insightsData, null, 2)}`;

return [{
  json: {
    model: "claude-opus-4-5",
    max_tokens: 2000,
    system: systemPrompt,
    messages: [{ role: "user", content: userMessage }],
    insightsData: insightsData
  }
}];
